//! Codex app-server client — subprocess lifecycle and turn streaming.
//!
//! Ports the Elixir `SymphonyElixir.Codex.AppServer` module to idiomatic Rust.
//!
//! This module will be fully implemented in S05/T02 and S05/T03.
//! The stubs here define the public API surface so dependent modules compile.

use std::path::Path;

use crate::domain::{AgentEvent, CodexConfig, Issue};
use crate::error::{Result, SymphonyError};

// ── Public types ──────────────────────────────────────────────────────

/// Opaque handle to a running Codex app-server subprocess session.
///
/// Holds the subprocess I/O channels and session state needed to run turns.
/// Created by `start_session`; consumed by `stop_session`.
pub struct SessionHandle {
    /// Session identifier returned by the Codex initialize handshake.
    pub session_id: String,
    // Additional fields (subprocess stdin/stdout, channels) added in T02.
}

/// The outcome of a completed Codex agent turn.
///
/// Contains the turn's event stream output, final text, and token accounting.
pub struct TurnResult {
    /// Events emitted during the turn, in delivery order.
    pub events: Vec<AgentEvent>,
    /// Final text output from the turn (if any).
    pub output_text: Option<String>,
    /// Total tokens consumed during the turn (input + output).
    pub total_tokens: u64,
}

// ── Public API ────────────────────────────────────────────────────────

/// Launch a Codex app-server subprocess and perform the startup handshake.
///
/// Sends `initialize` → awaits `initialized` → sends `thread/start` + `turn/start`.
/// Returns a `SessionHandle` on success.
///
/// # Errors
/// - `CodexNotFound` — the configured command does not exist on PATH
/// - `InvalidWorkspaceCwd` — workspace path is invalid or not a directory
/// - `ResponseTimeout` — handshake did not complete within the configured timeout
/// - `ResponseError` — subprocess sent an unexpected response during handshake
pub async fn start_session(
    _config: &CodexConfig,
    _issue: &Issue,
    _workspace_path: &Path,
) -> Result<SessionHandle> {
    Err(SymphonyError::Other(
        "app_server::start_session not yet implemented (S05/T02)".to_string(),
    ))
}

/// Run a single agent turn and stream events via the provided callback.
///
/// Sends the turn prompt and reads line-delimited JSON events until the turn
/// completes, fails, or times out.
///
/// # Errors
/// - `TurnFailed` — turn ended with an error response
/// - `TurnCancelled` — turn was cancelled by the orchestrator
/// - `TurnInputRequired` — turn requires interactive user input
/// - `TurnTimeout` — turn did not complete within the configured timeout
/// - `PortExit` — subprocess exited unexpectedly
pub async fn run_turn<F>(
    _handle: &mut SessionHandle,
    _prompt: &str,
    _event_callback: F,
) -> Result<TurnResult>
where
    F: FnMut(AgentEvent) + Send,
{
    Err(SymphonyError::Other(
        "app_server::run_turn not yet implemented (S05/T02)".to_string(),
    ))
}

/// Gracefully stop a Codex app-server session.
///
/// Sends a shutdown signal to the subprocess and waits for it to exit.
/// Consumes the `SessionHandle`.
///
/// # Errors
/// - `PortExit` — subprocess exited with a non-zero status
pub async fn stop_session(_handle: SessionHandle) -> Result<()> {
    Err(SymphonyError::Other(
        "app_server::stop_session not yet implemented (S05/T02)".to_string(),
    ))
}

use chrono::{DateTime, Utc};
use serde::{Deserialize, Serialize};
use std::collections::{BTreeMap, BTreeSet, HashMap, HashSet};
use std::fmt;
use std::ops::Deref;

// ── Issue (spec §4.1.1) ────────────────────────────────────────────────

/// Normalized issue record from the tracker.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Issue {
    pub id: String,
    pub identifier: String,
    pub title: String,
    #[serde(default)]
    pub description: Option<String>,
    #[serde(default)]
    pub priority: Option<i32>,
    pub state: String,
    #[serde(default)]
    pub branch_name: Option<String>,
    #[serde(default)]
    pub url: Option<String>,
    #[serde(default)]
    pub assignee_id: Option<String>,
    #[serde(default)]
    pub labels: Vec<String>,
    #[serde(default)]
    pub blocked_by: Vec<BlockerRef>,
    /// Whether this issue is routable to this worker (assignee filter).
    #[serde(default = "default_true")]
    pub assigned_to_worker: bool,
    #[serde(default)]
    pub created_at: Option<DateTime<Utc>>,
    #[serde(default)]
    pub updated_at: Option<DateTime<Utc>>,
}

fn default_true() -> bool {
    true
}

/// A blocker reference from an inverse relation.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BlockerRef {
    pub id: Option<String>,
    pub identifier: Option<String>,
    pub state: Option<String>,
}

// ── ApiKey ─────────────────────────────────────────────────────────────

/// A redacted API-key value.
///
/// `Debug` always prints `[REDACTED]` so the raw key can never leak into
/// tracing/log output, even via `{:?}` on a type that transitively contains
/// this field.  Use [`as_str`](ApiKey::as_str) or the `Deref<Target = str>`
/// impl to access the underlying value.
#[derive(Clone)]
pub struct ApiKey(String);

impl ApiKey {
    pub fn new(s: impl Into<String>) -> Self {
        ApiKey(s.into())
    }
    pub fn as_str(&self) -> &str {
        &self.0
    }
    pub fn into_string(self) -> String {
        self.0
    }
}

impl fmt::Debug for ApiKey {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.write_str("[REDACTED]")
    }
}

impl PartialEq for ApiKey {
    fn eq(&self, other: &Self) -> bool {
        self.0 == other.0
    }
}

impl Deref for ApiKey {
    type Target = str;
    fn deref(&self) -> &str {
        &self.0
    }
}

impl From<String> for ApiKey {
    fn from(s: String) -> Self {
        ApiKey(s)
    }
}

impl From<&str> for ApiKey {
    fn from(s: &str) -> Self {
        ApiKey(s.to_string())
    }
}

// ── Workflow Definition (spec §4.1.2) ──────────────────────────────────

/// Parsed WORKFLOW.md payload.
#[derive(Debug, Clone)]
pub struct WorkflowDefinition {
    /// YAML front matter as a raw map.
    pub config: serde_yaml::Value,
    /// Markdown body after front matter, trimmed.
    pub prompt_template: String,
}

// ── Service Config (spec §4.1.3 + §5.3) ───────────────────────────────

/// Top-level typed runtime config derived from WorkflowDefinition.config.
#[derive(Debug, Clone, Default)]
pub struct ServiceConfig {
    pub tracker: TrackerConfig,
    pub polling: PollingConfig,
    pub workspace: WorkspaceConfig,
    pub worker: WorkerConfig,
    pub agent: AgentConfig,
    pub codex: CodexConfig,
    pub hooks: HooksConfig,
    pub server: ServerConfig,
}

/// Tracker configuration (spec §5.3.1).
#[derive(Debug, Clone)]
pub struct TrackerConfig {
    pub kind: Option<String>,
    pub endpoint: String,
    /// The Linear API key.  Stored as [`ApiKey`] so it cannot accidentally
    /// appear in debug/tracing output — `{:?}` on this struct prints `[REDACTED]`.
    pub api_key: Option<ApiKey>,
    pub project_slug: Option<String>,
    pub assignee: Option<String>,
    pub active_states: Vec<String>,
    pub terminal_states: Vec<String>,
}

impl Default for TrackerConfig {
    fn default() -> Self {
        Self {
            kind: None,
            endpoint: "https://api.linear.app/graphql".to_string(),
            api_key: None,
            project_slug: None,
            assignee: None,
            active_states: vec!["Todo".to_string(), "In Progress".to_string()],
            terminal_states: vec![
                "Closed".to_string(),
                "Cancelled".to_string(),
                "Canceled".to_string(),
                "Duplicate".to_string(),
                "Done".to_string(),
            ],
        }
    }
}

/// Polling configuration (spec §5.3.2).
#[derive(Debug, Clone)]
pub struct PollingConfig {
    pub interval_ms: u64,
}

impl Default for PollingConfig {
    fn default() -> Self {
        Self {
            interval_ms: 30_000,
        }
    }
}

/// Workspace configuration (spec §5.3.3).
#[derive(Debug, Clone)]
pub struct WorkspaceConfig {
    pub root: String,
}

impl Default for WorkspaceConfig {
    fn default() -> Self {
        Self {
            root: default_workspace_root(),
        }
    }
}

fn default_workspace_root() -> String {
    let tmp = std::env::temp_dir();
    tmp.join("symphony_workspaces")
        .to_string_lossy()
        .to_string()
}

/// Worker configuration (SSH extension, spec §5.3 + Appendix A).
#[derive(Debug, Clone, Default)]
pub struct WorkerConfig {
    pub ssh_hosts: Vec<String>,
    pub max_concurrent_agents_per_host: Option<u32>,
}

/// Agent configuration (spec §5.3.5).
#[derive(Debug, Clone)]
pub struct AgentConfig {
    pub max_concurrent_agents: u32,
    pub max_turns: u32,
    pub max_retry_backoff_ms: u64,
    pub max_concurrent_agents_by_state: HashMap<String, u32>,
}

impl Default for AgentConfig {
    fn default() -> Self {
        Self {
            max_concurrent_agents: 10,
            max_turns: 20,
            max_retry_backoff_ms: 300_000,
            max_concurrent_agents_by_state: HashMap::new(),
        }
    }
}

/// Codex app-server configuration (spec §5.3.6).
#[derive(Debug, Clone)]
pub struct CodexConfig {
    /// Command and arguments used to launch the Codex app-server process.
    /// Stored as a list to enable exec-without-shell semantics (spec §5.3.6).
    /// The YAML field accepts either a string (`"codex app-server"`, split on
    /// whitespace) or an explicit list (`["codex", "app-server"]`).
    pub command: Vec<String>,
    pub approval_policy: serde_json::Value,
    pub thread_sandbox: String,
    pub turn_sandbox_policy: Option<serde_json::Value>,
    pub turn_timeout_ms: u64,
    pub read_timeout_ms: u64,
    pub stall_timeout_ms: u64,
}

impl Default for CodexConfig {
    fn default() -> Self {
        Self {
            command: vec!["codex".to_string(), "app-server".to_string()],
            approval_policy: serde_json::json!({
                "reject": {
                    "sandbox_approval": true,
                    "rules": true,
                    "mcp_elicitations": true
                }
            }),
            thread_sandbox: "workspace-write".to_string(),
            turn_sandbox_policy: None,
            turn_timeout_ms: 3_600_000,
            read_timeout_ms: 5_000,
            stall_timeout_ms: 300_000,
        }
    }
}

/// Hooks configuration (spec §5.3.4).
#[derive(Debug, Clone)]
pub struct HooksConfig {
    pub after_create: Option<String>,
    pub before_run: Option<String>,
    pub after_run: Option<String>,
    pub before_remove: Option<String>,
    pub timeout_ms: u64,
}

impl Default for HooksConfig {
    fn default() -> Self {
        Self {
            after_create: None,
            before_run: None,
            after_run: None,
            before_remove: None,
            timeout_ms: 60_000,
        }
    }
}

/// Server configuration (extension, spec §13.7).
#[derive(Debug, Clone)]
pub struct ServerConfig {
    pub port: Option<u16>,
    pub host: String,
}

impl Default for ServerConfig {
    fn default() -> Self {
        Self {
            port: None,
            host: "127.0.0.1".to_string(),
        }
    }
}

// ── Workspace (spec §4.1.4) ───────────────────────────────────────────

/// A prepared workspace directory for an issue run.
#[derive(Debug, Clone)]
pub struct Workspace {
    pub path: String,
    pub workspace_key: String,
    pub created_now: bool,
}

// ── RunAttempt (spec §4.1.5) ──────────────────────────────────────────

/// A single execution attempt for an issue.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RunAttempt {
    pub issue_id: String,
    pub issue_identifier: String,
    /// `None` for first attempt, `Some(n)` for retries.
    #[serde(default)]
    pub attempt: Option<u32>,
    pub workspace_path: String,
    pub started_at: DateTime<Utc>,
    pub status: String,
    #[serde(default)]
    pub error: Option<String>,
    #[serde(default)]
    pub worker_host: Option<String>,
}

// ── LiveSession (spec §4.1.6) ─────────────────────────────────────────

/// Tracks the active Codex session for a running issue.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct LiveSession {
    pub session_id: String,
    pub thread_id: String,
    pub turn_id: String,
    #[serde(default)]
    pub codex_app_server_pid: Option<String>,
    #[serde(default)]
    pub last_codex_event: Option<String>,
    #[serde(default)]
    pub last_codex_timestamp: Option<DateTime<Utc>>,
    #[serde(default)]
    pub last_codex_message: Option<String>,
    #[serde(default)]
    pub codex_input_tokens: u64,
    #[serde(default)]
    pub codex_output_tokens: u64,
    #[serde(default)]
    pub codex_total_tokens: u64,
    #[serde(default)]
    pub last_reported_input_tokens: u64,
    #[serde(default)]
    pub last_reported_output_tokens: u64,
    #[serde(default)]
    pub last_reported_total_tokens: u64,
    #[serde(default)]
    pub turn_count: u32,
    pub started_at: DateTime<Utc>,
    #[serde(default)]
    pub worker_host: Option<String>,
}

// ── RetryEntry (spec §4.1.7) ──────────────────────────────────────────

/// An issue queued for retry after a failed attempt.
#[derive(Debug, Clone)]
pub struct RetryEntry {
    pub issue_id: String,
    pub identifier: String,
    pub attempt: u32,
    /// Monotonic millisecond timestamp when retry is due.
    pub due_at_ms: i64,
    /// Opaque handle — concrete type wired in S06.
    pub timer_handle: Option<String>,
    pub error: Option<String>,
    pub worker_host: Option<String>,
    pub workspace_path: Option<String>,
}

// ── CodexTotals ───────────────────────────────────────────────────────

/// Aggregate token and time accounting across all agent sessions.
#[derive(Debug, Clone, Serialize, Deserialize, Default)]
pub struct CodexTotals {
    pub input_tokens: u64,
    pub output_tokens: u64,
    pub total_tokens: u64,
    pub seconds_running: f64,
}

// ── RateLimitInfo ─────────────────────────────────────────────────────

/// Opaque rate-limit snapshot captured from agent events.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RateLimitInfo {
    pub data: serde_json::Value,
}

// ── OrchestratorState (spec §4.1.8) ───────────────────────────────────

/// Mutable runtime state of the orchestrator loop.
#[derive(Debug, Clone)]
pub struct OrchestratorState {
    pub poll_interval_ms: u64,
    pub max_concurrent_agents: u32,
    pub running: HashMap<String, RunAttempt>,
    pub claimed: HashSet<String>,
    pub retry_attempts: HashMap<String, RetryEntry>,
    pub completed: HashSet<String>,
    pub codex_totals: CodexTotals,
    pub codex_rate_limits: Option<RateLimitInfo>,
}

// ── OrchestratorSnapshot (S06→S07 boundary) ───────────────────────────

/// A single retry entry in the snapshot (sorted, serializable).
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RetrySnapshotEntry {
    pub issue_id: String,
    pub identifier: String,
    pub attempt: u32,
    pub due_in_ms: i64,
    pub error: Option<String>,
    pub worker_host: Option<String>,
    pub workspace_path: Option<String>,
}

/// Polling state for the snapshot.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PollingSnapshot {
    pub checking: bool,
    pub next_poll_in_ms: i64,
    pub poll_interval_ms: u64,
}

/// Read-only serializable view of orchestrator state for the HTTP API.
/// Uses `BTreeMap` for deterministic JSON key ordering.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct OrchestratorSnapshot {
    pub poll_interval_ms: u64,
    pub max_concurrent_agents: u32,
    pub running: BTreeMap<String, RunAttempt>,
    pub claimed: BTreeSet<String>,
    pub retry_queue: Vec<RetrySnapshotEntry>,
    pub completed: BTreeSet<String>,
    pub codex_totals: CodexTotals,
    pub codex_rate_limits: Option<RateLimitInfo>,
    pub polling: PollingSnapshot,
}

// ── AgentEvent (spec §10.4) ───────────────────────────────────────────

/// Events emitted by a Codex agent session, parsed from the event stream.
#[derive(Debug, Clone)]
pub enum AgentEvent {
    SessionStarted {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        session_id: String,
    },
    StartupFailed {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        error: String,
    },
    TurnCompleted {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        turn_id: String,
        message: Option<String>,
    },
    TurnFailed {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        turn_id: String,
        error: String,
    },
    TurnCancelled {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        turn_id: String,
    },
    TurnEndedWithError {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        turn_id: String,
        error: String,
    },
    TurnInputRequired {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        turn_id: String,
        prompt: Option<String>,
    },
    ApprovalAutoApproved {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        tool_call: String,
    },
    UnsupportedToolCall {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        tool_name: String,
    },
    Notification {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        message: String,
    },
    OtherMessage {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        raw: serde_json::Value,
    },
    Malformed {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        raw_text: String,
        parse_error: String,
    },
}

//! Path safety utilities — sanitize identifiers and canonicalize paths
//! with segment-by-segment symlink resolution.
//!
//! This module provides Elixir `PathSafety` parity (spec §8.1):
//! - `sanitize_identifier`: replaces unsafe characters for filesystem paths
//! - `canonicalize`: resolves symlinks segment-by-segment, tolerating
//!   non-existent tail segments (unlike `std::fs::canonicalize`)

use regex::Regex;
use std::path::{Component, Path, PathBuf};
use std::sync::LazyLock;

use crate::error::{Result, SymphonyError};

/// Regex matching characters NOT in the safe set `[A-Za-z0-9._-]`.
static UNSAFE_CHARS: LazyLock<Regex> =
    LazyLock::new(|| Regex::new(r"[^A-Za-z0-9._-]").expect("invalid regex"));

/// Replace characters outside `[A-Za-z0-9._-]` with `_`.
/// Empty or whitespace-only input returns `"issue"`.
pub fn sanitize_identifier(id: &str) -> String {
    let trimmed = id.trim();
    if trimmed.is_empty() {
        return "issue".to_string();
    }
    UNSAFE_CHARS.replace_all(trimmed, "_").into_owned()
}

/// Maximum number of symlink hops before we assume a cycle and bail out.
const MAX_SYMLINK_HOPS: u32 = 40;

/// Canonicalize a path by resolving symlinks segment-by-segment.
///
/// Unlike `std::fs::canonicalize`, this function tolerates non-existent
/// tail segments: it resolves the existing prefix via symlink traversal,
/// then appends any remaining segments literally.
///
/// Handles `.` (skip) and `..` (pop) components correctly, matching
/// Elixir `Path.expand` + `PathSafety.canonicalize/1` behavior.
/// Detects symlink cycles via a hop counter (max 40 hops).
pub fn canonicalize(path: &Path) -> Result<PathBuf> {
    // Expand to absolute path (resolve relative to cwd)
    let expanded = if path.is_absolute() {
        path.to_path_buf()
    } else {
        std::env::current_dir()
            .map_err(SymphonyError::Io)?
            .join(path)
    };

    // Split into root and segments, folding . and ..
    let (root, segments) = split_and_normalize(&expanded)?;

    let seg_refs: Vec<&std::ffi::OsStr> = segments.iter().map(|s| s.as_os_str()).collect();
    resolve_segments(&root, &[], &seg_refs, MAX_SYMLINK_HOPS)
}

/// Split an absolute path into root + normalized segments.
/// Handles `.` (skip) and `..` (pop last normal segment).
fn split_and_normalize(path: &Path) -> Result<(PathBuf, Vec<std::ffi::OsString>)> {
    let mut components = path.components();
    let root = match components.next() {
        Some(Component::RootDir) => PathBuf::from("/"),
        Some(Component::Prefix(p)) => {
            let mut r = PathBuf::from(p.as_os_str());
            if let Some(Component::RootDir) = components.clone().next() {
                components.next();
                r.push(std::path::MAIN_SEPARATOR_STR);
            }
            r
        }
        _ => {
            return Err(SymphonyError::Other(format!(
                "path_canonicalize_failed: not absolute: {}",
                path.display()
            )));
        }
    };

    let mut segments: Vec<std::ffi::OsString> = Vec::new();
    for c in components {
        match c {
            Component::Normal(s) => segments.push(s.to_os_string()),
            Component::ParentDir => {
                segments.pop();
            }
            Component::CurDir => { /* skip */ }
            _ => {}
        }
    }

    Ok((root, segments))
}

/// Recursively resolve path segments, following symlinks.
/// `hops_remaining` prevents infinite recursion on symlink cycles.
fn resolve_segments(
    root: &Path,
    resolved: &[&std::ffi::OsStr],
    remaining: &[&std::ffi::OsStr],
    hops_remaining: u32,
) -> Result<PathBuf> {
    if remaining.is_empty() {
        return Ok(join_path(root, resolved));
    }

    let segment = remaining[0];
    let rest = &remaining[1..];

    let candidate = {
        let mut parts: Vec<&std::ffi::OsStr> = resolved.to_vec();
        parts.push(segment);
        join_path(root, &parts)
    };

    // Use lstat (symlink_metadata) — does NOT follow symlinks
    match std::fs::symlink_metadata(&candidate) {
        Ok(meta) if meta.file_type().is_symlink() => {
            if hops_remaining == 0 {
                return Err(SymphonyError::Other(format!(
                    "symlink_loop: too many symlink hops resolving {}",
                    candidate.display()
                )));
            }

            // Read the symlink target
            let target = std::fs::read_link(&candidate).map_err(SymphonyError::Io)?;

            // Resolve relative symlink targets against the current resolved base
            let resolved_target = if target.is_absolute() {
                target
            } else {
                join_path(root, resolved).join(&target)
            };

            // Normalize the resolved target (handles . and .. in symlink targets)
            let (target_root, target_segments) = split_and_normalize(&resolved_target)?;

            // Combine target segments + remaining original segments
            let mut combined_owned: Vec<std::ffi::OsString> = target_segments;
            combined_owned.extend(rest.iter().map(|s| s.to_os_string()));

            let combined_refs: Vec<&std::ffi::OsStr> =
                combined_owned.iter().map(|s| s.as_os_str()).collect();

            resolve_segments(&target_root, &[], &combined_refs, hops_remaining - 1)
        }
        Ok(_) => {
            // Regular file or directory — add to resolved and continue
            let mut new_resolved: Vec<&std::ffi::OsStr> = resolved.to_vec();
            new_resolved.push(segment);
            resolve_segments(root, &new_resolved, rest, hops_remaining)
        }
        Err(e) if e.kind() == std::io::ErrorKind::NotFound => {
            // Non-existent segment — return the joined path with remaining segments
            let mut all: Vec<&std::ffi::OsStr> = resolved.to_vec();
            all.push(segment);
            all.extend_from_slice(rest);
            Ok(join_path(root, &all))
        }
        Err(e) => Err(SymphonyError::Io(e)),
    }
}

/// Join root path with a slice of segments.
fn join_path(root: &Path, segments: &[&std::ffi::OsStr]) -> PathBuf {
    let mut path = root.to_path_buf();
    for seg in segments {
        path.push(seg);
    }
    path
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_sanitize_replaces_unsafe() {
        assert_eq!(sanitize_identifier("MT/Det"), "MT_Det");
        assert_eq!(sanitize_identifier("S-1"), "S-1");
        assert_eq!(sanitize_identifier("hello world!"), "hello_world_");
        assert_eq!(sanitize_identifier("a/b\\c:d"), "a_b_c_d");
    }

    #[test]
    fn test_sanitize_empty() {
        assert_eq!(sanitize_identifier(""), "issue");
        assert_eq!(sanitize_identifier("  "), "issue");
    }

    #[test]
    fn test_sanitize_preserves_safe_chars() {
        assert_eq!(sanitize_identifier("abc-123.txt_v2"), "abc-123.txt_v2");
    }
}

//! Dynamic tool dispatch for Codex agent sessions.
//!
//! Ports the Elixir `SymphonyElixir.Codex.DynamicTool` module to idiomatic Rust.
//!
//! This module handles client-side tool calls requested by the Codex app-server.
//! Currently supports a single tool: `linear_graphql`.
//!
//! The `execute` function accepts a generic `executor` closure so that the Linear
//! GraphQL call can be injected in tests without a real HTTP client.

use std::future::Future;

use serde::{Deserialize, Serialize};
use serde_json::{json, Value};

use crate::error::SymphonyError;

// ── Constants ─────────────────────────────────────────────────────────

const LINEAR_GRAPHQL_TOOL: &str = "linear_graphql";

const LINEAR_GRAPHQL_DESCRIPTION: &str =
    "Execute a raw GraphQL query or mutation against Linear using Symphony's configured auth.";

// ── Public types ──────────────────────────────────────────────────────

/// A single content item in a tool result, matching the Codex protocol schema.
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub struct ContentItem {
    /// Content type tag — always `"inputText"` for text responses.
    #[serde(rename = "type")]
    pub item_type: String,
    /// The text payload, identical to `ToolResult::output`.
    pub text: String,
}

/// The result returned by `execute`, matching the Codex dynamic-tool protocol.
///
/// Serialises to camelCase JSON: `{ "success": bool, "output": "...", "contentItems": [...] }`.
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
#[serde(rename_all = "camelCase")]
pub struct ToolResult {
    /// Whether the tool call succeeded.
    pub success: bool,
    /// JSON-encoded payload (pretty-printed) or inspect-style fallback.
    pub output: String,
    /// Structured content items for the Codex protocol.
    pub content_items: Vec<ContentItem>,
}

// ── Public API ────────────────────────────────────────────────────────

/// Return the list of tool specifications advertised to the Codex app-server.
///
/// Matches the Elixir `tool_specs/0` function. Each spec has `name`, `description`,
/// and `inputSchema` conforming to the JSON Schema draft used by the Codex protocol.
pub fn tool_specs() -> Vec<Value> {
    vec![json!({
        "name": LINEAR_GRAPHQL_TOOL,
        "description": LINEAR_GRAPHQL_DESCRIPTION,
        "inputSchema": {
            "type": "object",
            "additionalProperties": false,
            "required": ["query"],
            "properties": {
                "query": {
                    "type": "string",
                    "description": "GraphQL query or mutation document to execute against Linear."
                },
                "variables": {
                    "type": ["object", "null"],
                    "description": "Optional GraphQL variables object.",
                    "additionalProperties": true
                }
            }
        }
    })]
}

/// Dispatch a dynamic tool call.
///
/// # Arguments
/// - `tool_name` — the name of the tool requested by Codex
/// - `arguments`  — raw arguments value (string, object, or other) from the tool call
/// - `executor`   — async closure used to execute a GraphQL query; injected for testability
///
/// Returns a `ToolResult` that always contains `success`, `output`, and `content_items`.
/// Never returns an error — all failure conditions are encoded in the `ToolResult` payload.
///
/// ## Argument normalization (mirrors Elixir `normalize_linear_graphql_arguments/1`)
/// - `Value::String(s)` — treated as a raw query; must be non-empty after trimming
/// - `Value::Object(m)` — must have `"query"` key (non-empty string) + optional `"variables"` (object)
/// - anything else — `invalid_arguments` error
pub async fn execute<F, Fut>(
    tool_name: &str,
    arguments: Value,
    executor: F,
) -> ToolResult
where
    F: FnOnce(String, Value) -> Fut,
    Fut: Future<Output = Result<Value, SymphonyError>>,
{
    match tool_name {
        LINEAR_GRAPHQL_TOOL => execute_linear_graphql(arguments, executor).await,
        other => failure_result(json!({
            "error": {
                "message": format!("Unsupported dynamic tool: {:?}.", other),
                "supportedTools": supported_tool_names()
            }
        })),
    }
}

// ── Internal: linear_graphql ──────────────────────────────────────────

async fn execute_linear_graphql<F, Fut>(arguments: Value, executor: F) -> ToolResult
where
    F: FnOnce(String, Value) -> Fut,
    Fut: Future<Output = Result<Value, SymphonyError>>,
{
    match normalize_linear_graphql_arguments(arguments) {
        Ok((query, variables)) => match executor(query, variables).await {
            Ok(response) => graphql_result(response),
            Err(err) => failure_result(tool_error_payload(&err)),
        },
        Err(err) => failure_result(tool_error_payload(&err)),
    }
}

/// Normalise `linear_graphql` arguments into `(query, variables)`.
///
/// Mirrors Elixir's `normalize_linear_graphql_arguments/1` with all three clauses:
/// 1. Binary (string) → trim and use as query with empty variables
/// 2. Map → extract `query` (required, non-empty) + `variables` (optional object)
/// 3. Anything else → `invalid_arguments`
fn normalize_linear_graphql_arguments(
    arguments: Value,
) -> Result<(String, Value), SymphonyError> {
    match arguments {
        Value::String(s) => {
            let trimmed = s.trim().to_string();
            if trimmed.is_empty() {
                Err(SymphonyError::Other("missing_query".to_string()))
            } else {
                Ok((trimmed, json!({})))
            }
        }
        Value::Object(ref map) => {
            // Extract query
            let query = match map.get("query").or_else(|| map.get("query")) {
                Some(Value::String(q)) => {
                    let trimmed = q.trim().to_string();
                    if trimmed.is_empty() {
                        return Err(SymphonyError::Other("missing_query".to_string()));
                    }
                    trimmed
                }
                _ => return Err(SymphonyError::Other("missing_query".to_string())),
            };

            // Extract variables (optional, must be object if present)
            let variables = match map.get("variables") {
                None => json!({}),
                Some(Value::Object(_)) => map.get("variables").unwrap().clone(),
                Some(Value::Null) => json!({}),
                Some(_) => return Err(SymphonyError::Other("invalid_variables".to_string())),
            };

            Ok((query, variables))
        }
        _ => Err(SymphonyError::Other("invalid_arguments".to_string())),
    }
}

// ── Internal: response encoding ───────────────────────────────────────

/// Build a `ToolResult` from a raw GraphQL response body.
///
/// Sets `success = false` when the body contains a non-empty `errors` list
/// (checking both string and atom keys to mirror the Elixir reference).
/// The body is always preserved verbatim in `output`.
fn graphql_result(response: Value) -> ToolResult {
    let has_errors = match &response {
        Value::Object(m) => {
            if let Some(errors) = m.get("errors") {
                match errors {
                    Value::Array(arr) => !arr.is_empty(),
                    _ => false,
                }
            } else {
                false
            }
        }
        _ => false,
    };

    let output = encode_payload(&response);
    build_result(!has_errors, output)
}

/// Build a failure `ToolResult` from a structured error payload.
fn failure_result(payload: Value) -> ToolResult {
    let output = encode_payload(&payload);
    build_result(false, output)
}

/// Construct the final `ToolResult` with the `contentItems` array.
fn build_result(success: bool, output: String) -> ToolResult {
    ToolResult {
        success,
        content_items: vec![ContentItem {
            item_type: "inputText".to_string(),
            text: output.clone(),
        }],
        output,
    }
}

/// Serialise a JSON payload to a pretty-printed string.
///
/// Falls back to `Debug` formatting for non-serialisable values (should not
/// occur with `serde_json::Value` but matches Elixir's `inspect` fallback).
fn encode_payload(payload: &Value) -> String {
    serde_json::to_string_pretty(payload).unwrap_or_else(|_| format!("{payload:?}"))
}

// ── Internal: error formatting ────────────────────────────────────────

/// Map a `SymphonyError` (or our internal sentinel errors) to the tool error payload.
///
/// Mirrors Elixir's `tool_error_payload/1` clauses exactly, including error messages.
fn tool_error_payload(err: &SymphonyError) -> Value {
    // Internal sentinel errors from argument normalisation are stored as Other("...").
    if let SymphonyError::Other(tag) = err {
        match tag.as_str() {
            "missing_query" => {
                return json!({
                    "error": {
                        "message": "`linear_graphql` requires a non-empty `query` string."
                    }
                })
            }
            "invalid_arguments" => {
                return json!({
                    "error": {
                        "message": "`linear_graphql` expects either a GraphQL query string or an object with `query` and optional `variables`."
                    }
                })
            }
            "invalid_variables" => {
                return json!({
                    "error": {
                        "message": "`linear_graphql.variables` must be a JSON object when provided."
                    }
                })
            }
            _ => {}
        }
    }

    match err {
        SymphonyError::MissingLinearApiToken => json!({
            "error": {
                "message": "Symphony is missing Linear auth. Set `linear.api_key` in `WORKFLOW.md` or export `LINEAR_API_KEY`."
            }
        }),
        SymphonyError::LinearApiStatus(status) => json!({
            "error": {
                "message": format!("Linear GraphQL request failed with HTTP {}.", status),
                "status": status
            }
        }),
        SymphonyError::LinearApiRequest(reason) => json!({
            "error": {
                "message": "Linear GraphQL request failed before receiving a successful response.",
                "reason": reason
            }
        }),
        other => json!({
            "error": {
                "message": "Linear GraphQL tool execution failed.",
                "reason": other.to_string()
            }
        }),
    }
}

// ── Internal helpers ──────────────────────────────────────────────────

fn supported_tool_names() -> Vec<String> {
    tool_specs()
        .iter()
        .filter_map(|spec| spec.get("name")?.as_str().map(|s| s.to_string()))
        .collect()
}

